#include <stdio.h>
int main() {
    int N;
    long long M;
    scanf("%d %lld", &N, &M);
    long long A[N], B[N];
    for (int i = 0; i < N; i++) {
        scanf("%lld", &A[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%lld", &B[i]);
    }
    long long low = 0, high = 0;
    for (int i = 0; i < N; i++) {
        high = (high > A[i] * B[i]) ? high : A[i] * B[i];
    }
    long long ans = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        long long total = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] * B[i] <= mid) {
                total += A[i];
            } else {
                total += (A[i] - (mid / B[i]));
            }
        }
        if (total <= M) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    printf("%lld\n", ans);
    return 0;
}

